Here is a straightforward caching system that includes a Time-To-Live (TTL) so your data doesn't get stale, along with an example of how to use it with your weather API calls.

### 1. The Simple Cache Utility (`cache.js`)

This class handles saving data to `localStorage`, tracking when it expires, and fetching it back safely.

```javascript
class SimpleCache {
  constructor(prefix = 'cache_') {
    this.prefix = prefix;
  }

  /**
   * Save data to cache with an expiration time.
   * @param {string} key - The cache key (e.g., city name)
   * @param {any} data - The data to store
   * @param {number} ttlInMinutes - Time-to-live in minutes
   */
  set(key, data, ttlInMinutes = 10) {
    const item = {
      data: data,
      expiry: Date.now() + (ttlInMinutes * 60 * 1000)
    };
    try {
      localStorage.setItem(this.prefix + key, JSON.stringify(item));
    } catch (error) {
      console.error('Failed to set cache:', error);
    }
  }

  /**
   * Get data from cache. Returns null if expired or not found.
   * @param {string} key - The cache key
   * @returns {any|null}
   */
  get(key) {
    const cachedItem = localStorage.getItem(this.prefix + key);
    if (!cachedItem) return null;

    const item = JSON.parse(cachedItem);

    // If the data is expired, remove it and return null
    if (Date.now() > item.expiry) {
      localStorage.removeItem(this.prefix + key);
      return null;
    }

    return item.data;
  }

  /**
   * Clear a specific cache entry.
   * @param {string} key - The cache key
   */
  clear(key) {
    localStorage.removeItem(this.prefix + key);
  }
}

// Export an instance of the cache
export const apiCache = new SimpleCache('weather_app_');
```

